class Solution {
public:
    int countDigitOne(int n) {
        int res = 0;
        for (int i = 1; i <= n; i *= 10) {
            int div = n / (i * 10);
            res += div * i;
            int mod = n % (i * 10);
            res += std::min(std::max(mod / i, 0), 1);
        }
        return res;
    }
};
